<template>  <UiText v-if="loading" variant="rolesMuted">{{ loadingText }}</UiText>  <UiText v-else-if="roles.length === 0" variant="rolesMuted">{{ emptyText }}</UiText>  <UiGrid v-else variant="roles">    <RoleCard v-for="role in roles" :key="role.id" :role="role" @edit="$emit('edit', $event)" />  </UiGrid></template>